#!/usr/bin/env bash
# PhyJudge-score the trained videos generated by launch_v3_intermediate_regen.sh.
# Run this on juyi-finetune in the `physground` env, after mirroring the
# generated videos from juyi-videorl. Baselines reuse the v3 final-eval
# scores from results.jsonl (no re-score), so this only scores trained.
#
# Per-step wall ~6.5 min (42 videos × 5 axes × ~9.4s). 3 steps ≈ 20 min.
#
# Env overrides:
#   RUN_ROOT       v3_intermediate_<ts> dir mirrored from juyi-videorl (REQUIRED)
#   STEPS_TO_SCORE  space-separated steps (default: "50 100 150")
#   VIDEODPO_DIR   sibling videodpo checkout holding physground_score.py
#                  (default: $HOME/videodpo)
#   AXES           override default 5 axes
#   BATCH_AXES     pass-through to scorer (default: --batch-axes)

set -euo pipefail
# shellcheck source=_common.sh
source "$(dirname "${BASH_SOURCE[0]}")/_common.sh"

init_paths "${BASH_SOURCE[0]}"
activate_env physground
cd "$DPO_DIR"

if [[ -z "${RUN_ROOT:-}" ]]; then
  echo "FATAL: set RUN_ROOT to the v3_intermediate_<ts> dir mirrored from juyi-videorl" >&2
  exit 2
fi
if [[ ! -d "$RUN_ROOT" ]]; then
  echo "FATAL: RUN_ROOT=$RUN_ROOT does not exist" >&2
  exit 2
fi

VIDEODPO_DIR="${VIDEODPO_DIR:-$HOME/videodpo}"
SCORER="${SCORER:-$VIDEODPO_DIR/benchmark/physground_score.py}"
STEPS_TO_SCORE="${STEPS_TO_SCORE:-50 100 150}"
AXES="${AXES:-SA PTV persistence inertia momentum}"
BATCH_AXES="${BATCH_AXES:---batch-axes}"

if [[ ! -f "$SCORER" ]]; then
  echo "FATAL: scorer not found at $SCORER (set VIDEODPO_DIR or SCORER)" >&2
  exit 2
fi

{
  echo "[paths] RUN_ROOT=$RUN_ROOT"
  echo "[paths] SCORER=$SCORER"
  echo "[paths] STEPS_TO_SCORE='$STEPS_TO_SCORE'"
} | tee -a "$LOG_FILE"

for STEP in $STEPS_TO_SCORE; do
  RUN_GLOB="$RUN_ROOT/step${STEP}/*/heldout_regen/*/trained/**/manifest.json"
  OUT_DIR="$RUN_ROOT/scores/step${STEP}"
  echo "=== score step ${STEP} ===" | tee -a "$LOG_FILE"
  echo "[score] run-glob=$RUN_GLOB" | tee -a "$LOG_FILE"
  echo "[score] out-dir=$OUT_DIR" | tee -a "$LOG_FILE"
  mkdir -p "$OUT_DIR"
  # shellcheck disable=SC2086
  python "$SCORER" \
    --run-glob "$RUN_GLOB" \
    --axes $AXES \
    $BATCH_AXES \
    --out-dir "$OUT_DIR" \
    --skip-existing \
    2>&1 | tee -a "$LOG_FILE"
done

echo "[done] scoring complete -> $RUN_ROOT/scores/step{50,100,150}/<ts>/results.jsonl" | tee -a "$LOG_FILE"
echo "[next] python script/eval/analyze_intermediate_deltas.py --run-root $RUN_ROOT \\" | tee -a "$LOG_FILE"
echo "         --baseline-results <v3_full_strip>/scores/<ts>/results.jsonl" | tee -a "$LOG_FILE"
